create.query:
mutation StagedCatalogWriteCreateProduct($product: ProductCreateInput!) {
  productCreate(product: $product) {
    product {
      id
      title
      handle
      status
      vendor
      productType
    }
    userErrors {
      field
      message
    }
  }
}

catalogAfterCreate.query:
query StagedCatalogWriteCatalogRead($first: Int!) {
  productsCount {
    count
    precision
  }
  products(first: $first, sortKey: UPDATED_AT, reverse: true) {
    nodes {
      id
      title
      handle
      status
    }
  }
}

